{
  "nodeType": "nodes-base.emailReadImap",
  "workflowNodeType": "n8n-nodes-base.emailReadImap",
  "displayName": "Email Trigger (IMAP)",
  "description": "Triggers the workflow when a new email is received",
  "category": "trigger",
  "version": "2.1",
  "isVersioned": true,
  "versionNotice": "⚠️ Use typeVersion: 2.1 when creating this node",
  "requiredProperties": [],
  "commonProperties": [
    {
      "name": "mailbox",
      "displayName": "Mailbox Name",
      "type": "string",
      "description": "Mailbox Name",
      "required": false,
      "default": "INBOX"
    },
    {
      "name": "postProcessAction",
      "displayName": "Action",
      "type": "options",
      "description": "What to do after the email has been received. If \"nothing\" gets selected it will be processed multiple times.",
      "required": false,
      "default": "read",
      "options": [
        {
          "value": "read",
          "label": "Mark as Read"
        },
        {
          "value": "nothing",
          "label": "Nothing"
        }
      ]
    },
    {
      "name": "format",
      "displayName": "Format",
      "type": "options",
      "description": "The format to return the message in",
      "required": false,
      "default": "simple",
      "options": [
        {
          "value": "raw",
          "label": "RAW"
        },
        {
          "value": "resolved",
          "label": "Resolved"
        },
        {
          "value": "simple",
          "label": "Simple"
        }
      ]
    },
    {
      "name": "downloadAttachments",
      "displayName": "Download Attachments",
      "type": "boolean",
      "description": "Whether attachments of emails should be downloaded. Only set if needed as it increases processing.",
      "required": false,
      "default": false,
      "showWhen": {
        "format": [
          "simple"
        ]
      },
      "usageHint": "Enabling this will show additional options"
    },
    {
      "name": "dataPropertyAttachmentsPrefixName",
      "displayName": "Property Prefix Name",
      "type": "string",
      "description": "Prefix for name of the binary property to which to write the attachments. An index starting with 0 will be added. So if name is \"attachment_\" the first attachment is saved to \"attachment_0\"",
      "required": false,
      "default": "attachment_",
      "showWhen": {
        "format": [
          "resolved"
        ]
      }
    }
  ],
  "operations": [],
  "metadata": {
    "totalProperties": 7,
    "isAITool": true,
    "isTrigger": true,
    "isWebhook": false,
    "hasCredentials": true,
    "package": "n8n-nodes-base",
    "developmentStyle": "programmatic"
  },
  "versionInfo": {
    "currentVersion": "unknown",
    "totalVersions": 0,
    "hasVersionHistory": false
  }
}

