parameters.jsCode:
// Extract email metadata and build idempotence key
const email = $input.item.json;

// 1) Message-ID extraction (idempotence key)
let messageId = email.messageId || null;
if (!messageId) {
  // Fallback: deterministic hash from metadata
  const raw = String(email.from || '') + '|' + String(email.date || '') + '|' + String(email.subject || '');
  let hash = 0;
  for (let i = 0; i < raw.length; i++) {
    hash = ((hash << 5) - hash) + raw.charCodeAt(i);
    hash = hash & hash;
  }
  messageId = 'hash_' + Math.abs(hash).toString(16);
}

// 2) Parse address fields
const parseAddr = (f) => {
  if (!f) return '';
  if (typeof f === 'string') return f;
  if (f.text) return f.text;
  if (f.value && Array.isArray(f.value)) return f.value.map(v => v.address).join(', ');
  return JSON.stringify(f);
};

// 3) Attachments info from binary data
const bKeys = Object.keys($input.item.binary || {});
const attachments = bKeys.map(k => ({
  key: k,
  name: ($input.item.binary[k].fileName || k),
  mime: ($input.item.binary[k].mimeType || 'application/octet-stream')
}));

// 4) Body preview (max 500 chars)
const bodyPreview = (email.textPlain || email.text || '').substring(0, 500);

return {
  json: {
    message_id: messageId,
    from: parseAddr(email.from),
    to: parseAddr(email.to),
    cc: parseAddr(email.cc),
    subject: email.subject || '(sans sujet)',
    date: email.date ? new Date(email.date).toISOString() : new Date().toISOString(),
    body_preview: bodyPreview,
    has_attachments: bKeys.length > 0,
    attachments_count: bKeys.length,
    attachments_info: attachments
  },
  binary: $input.item.binary
};

// Build Notion API create page payload
const e = $('Prepare Email Data').item.json;
const dbId = $env.NOTION_EMAILS_DB_ID || 'REPLACE_WITH_EMAILS_DB_ID';
const sub = (s, n) => String(s || '').substring(0, n || 2000);

const payload = {
  parent: { database_id: dbId },
  properties: {
    message_id: { title: [{ text: { content: sub(e.message_id) } }] },
    from: { rich_text: [{ text: { content: sub(e.from) } }] },
    to: { rich_text: [{ text: { content: sub(e.to) } }] },
    cc: { rich_text: [{ text: { content: sub(e.cc) } }] },
    subject: { rich_text: [{ text: { content: sub(e.subject) } }] },
    date: { date: { start: e.date } },
    body_preview: { rich_text: [{ text: { content: sub(e.body_preview) } }] },
    has_attachments: { checkbox: e.has_attachments },
    attachments_count: { number: e.attachments_count },
    status_processing: { select: { name: 'NEW' } },
    account_id: { select: { name: 'default' } }
  }
};

return { json: { payload, email_data: e } };

// Restore binary data and prepare for S3 upload
const emailData = $('Prepare Email Data').item.json;
const binary = $('Prepare Email Data').item.binary || {};
const notionPageId = $('Create Email in Notion').item.json.id || 'unknown';
const safeId = emailData.message_id.replace(/[^a-zA-Z0-9_-]/g, '_');

const items = [];
for (const att of emailData.attachments_info || []) {
  if (binary[att.key]) {
    items.push({
      json: {
        message_id: emailData.message_id,
        notion_page_id: notionPageId,
        file_name: att.name,
        mime_type: att.mime,
        s3_key: 'emails/' + safeId + '/' + att.name
      },
      binary: { data: binary[att.key] }
    });
  }
}

if (items.length === 0) {
  return [{ json: { message: 'No binary data available' } }];
}
return items;

