parameters.jsCode:
// Extract Notion pages into individual items
const results = $input.first().json.results || [];

if (results.length === 0) {
  return [{ json: { _empty: true, message: 'Aucun email NEW a traiter' } }];
}

return results.map(page => {
  const p = page.properties || {};
  return {
    json: {
      notion_page_id: page.id,
      message_id: (p.message_id?.title?.[0]?.text?.content) || '',
      from: (p.from?.rich_text?.[0]?.text?.content) || '',
      to: (p.to?.rich_text?.[0]?.text?.content) || '',
      subject: (p.subject?.rich_text?.[0]?.text?.content) || '',
      date: (p.date?.date?.start) || '',
      body_preview: (p.body_preview?.rich_text?.[0]?.text?.content) || '',
      has_attachments: p.has_attachments?.checkbox || false,
      attachments_count: p.attachments_count?.number || 0
    }
  };
});

const email = $input.item.json;

if (email._empty) {
  return { json: { _skip: true } };
}

const prompt = `Analyse cet email et classifie-le pour la comptabilite.

EMAIL:
- De: ${email.from}
- Objet: ${email.subject}
- Date: ${email.date}
- Contenu: ${email.body_preview}
- Pieces jointes: ${email.has_attachments ? email.attachments_count + ' fichier(s)' : 'Aucune'}

Reponds UNIQUEMENT en JSON valide:
{
  "category": "invoice|contract|debt|other",
  "confidence": 0.0,
  "vendor": "string|null",
  "document_date": "YYYY-MM-DD|null",
  "amount": null,
  "currency": "EUR|USD|null",
  "needs_attachment_review": false,
  "tags": [],
  "rationale_short": "string"
}

REGLES:
- invoice: factures, notes de frais, recus
- contract: contrats, avenants, bons de commande
- debt: relances, mises en demeure, echeances
- other: newsletters, notifications, etc.
- confidence: 0.9+ tres sur, 0.5-0.9 probable, <0.5 incertain`;

return {
  json: {
    ...email,
    openai_payload: {
      model: 'gpt-4o-mini',
      messages: [
        { role: 'system', content: 'Tu es un assistant comptable expert. Reponds uniquement en JSON valide.' },
        { role: 'user', content: prompt }
      ],
      temperature: 0.1,
      response_format: { type: 'json_object' }
    }
  }
};

const email = $('Build LLM Prompt').item.json;

if (email._skip) {
  return { json: { _skip: true } };
}

let classification;
try {
  const content = $input.item.json.choices?.[0]?.message?.content || '{}';
  classification = JSON.parse(content);
} catch (e) {
  classification = {
    category: 'other',
    confidence: 0,
    vendor: null,
    document_date: null,
    amount: null,
    currency: null,
    needs_attachment_review: false,
    tags: ['parse_error'],
    rationale_short: 'Erreur parsing: ' + e.message
  };
}

// Determine status
let status = 'PROCESSED';
if (classification.confidence < 0.75 || classification.needs_attachment_review) {
  status = 'REVIEW';
}

const isAccounting = ['invoice', 'contract', 'debt'].includes(classification.category);

// Build update payload for Emails Index
const emailsDbId = $env.NOTION_EMAILS_DB_ID || 'REPLACE_WITH_EMAILS_DB_ID';
const docsDbId = $env.NOTION_DOCS_DB_ID || 'REPLACE_WITH_DOCS_DB_ID';
const sub = (s, n) => String(s || '').substring(0, n || 2000);

const updatePayload = {
  properties: {
    status_processing: { select: { name: status } },
    category: { select: { name: classification.category } }
  }
};
if (classification.vendor) updatePayload.properties.vendor = { rich_text: [{ text: { content: sub(classification.vendor) } }] };
if (classification.amount != null) updatePayload.properties.amount = { number: classification.amount };
if (classification.currency) updatePayload.properties.currency = { select: { name: classification.currency } };
if (classification.confidence != null) updatePayload.properties.confidence = { number: Math.round(classification.confidence * 100) / 100 };

// Build doc comptable payload (if accounting)
let docPayload = null;
if (isAccounting) {
  const docProps = {
    vendor: { title: [{ text: { content: sub(classification.vendor || email.from || 'Inconnu') } }] },
    type: { select: { name: classification.category } },
    status: { select: { name: 'a verifier' } },
    notes: { rich_text: [{ text: { content: sub(classification.rationale_short) } }] }
  };
  if (classification.amount != null) docProps.amount = { number: classification.amount };
  if (classification.currency) docProps.currency = { select: { name: classification.currency } };
  if (classification.document_date) docProps.date_document = { date: { start: classification.document_date } };
  docPayload = { parent: { database_id: docsDbId }, properties: docProps };
}

return {
  json: {
    notion_page_id: email.notion_page_id,
    message_id: email.message_id,
    classification,
    status,
    is_accounting: isAccounting,
    update_payload: updatePayload,
    doc_payload: docPayload
  }
};

